14	const survives = (wasAlive: boolean, liveNeighbors: number): boolean =>
15	  liveNeighbors === 3 || (wasAlive && liveNeighbors === 2);
16	
17	export function nextGeneration(cells: Cell[]): Cell[] {
18	  const aliveKeys = new Set(cells.map(keyOf));
19	  const neighborTally = new Map<string, { cell: Cell; count: number }>();
20	
21	  for (const cell of cells) {
22	    for (const neighbor of neighborsOf(cell)) {
23	      const k = keyOf(neighbor);
24	      const existing = neighborTally.get(k);
25	      neighborTally.set(k, { cell: neighbor, count: (existing?.count ?? 0) + 1 });
26	    }
27	  }
28	
29	  return [...neighborTally]
30	    .filter(([k, { count }]) => survives(aliveKeys.has(k), count))
